import React, { useLayoutEffect, useState } from "react";
import axios from "axios";
import { Table, Button, Checkbox } from "semantic-ui-react";
import { useActivityLogsTableHooks } from "./activity-logs-table-hooks";

const ActivityLogsTable = () => {
  const activityInfo = useActivityLogsTableHooks();

  return (
    <div title="Activity Logs">
      <Table selectable sortable>
        <Table.Header>
          <Table.Row>
            <Table.HeaderCell>ID</Table.HeaderCell>
            <Table.HeaderCell>Time Stamp</Table.HeaderCell>
            <Table.HeaderCell>Table Name</Table.HeaderCell>
            <Table.HeaderCell>Record ID</Table.HeaderCell>
            <Table.HeaderCell>Action</Table.HeaderCell>
            <Table.HeaderCell>Before Action</Table.HeaderCell>
            <Table.HeaderCell>After Action</Table.HeaderCell>
          </Table.Row>
        </Table.Header>
        <Table.Body>
          {activityInfo.map((part) => (
            <Table.Row key={part.id}>
              <Table.Cell>{part.id}</Table.Cell>
              <Table.Cell>{part.timestamp}</Table.Cell>
              <Table.Cell>{part.tableName}</Table.Cell>
              <Table.Cell>{part.recordId}</Table.Cell>
              <Table.Cell>{part.action}</Table.Cell>
              <Table.Cell>{part.valueBefore}</Table.Cell>
              <Table.Cell>{part.valueAfter}</Table.Cell>
            </Table.Row>
          ))}
        </Table.Body>
      </Table>
    </div>
  );
};

export default ActivityLogsTable;
